/*!
 * InnovaWise Labs — Triage Widget
 * Connects to backend at window.__IW_API_BASE__
 */
(function () {
  'use strict';

  var API_BASE = (window.__IW_API_BASE__ || '').replace(/\/$/, '');
  var BOT_NAME = window.__CHATBOT_NAME__ || 'InnovaWise Labs';
  var ACCENT   = '#00c4a0';
  var SESSION_KEY = 'iw_session_id';

  function getSession() {
    try { return sessionStorage.getItem(SESSION_KEY) || null; } catch(e) { return null; }
  }
  function setSession(id) {
    try { sessionStorage.setItem(SESSION_KEY, id); } catch(e) {}
  }

  var style = document.createElement('style');
  style.textContent = '#iw-launcher{position:fixed;bottom:24px;right:24px;z-index:9998;width:56px;height:56px;border-radius:50%;border:none;cursor:pointer;display:flex;align-items:center;justify-content:center;box-shadow:0 4px 16px rgba(0,0,0,.25);transition:transform .2s;}#iw-launcher:hover{transform:scale(1.08);}#iw-launcher svg{pointer-events:none;}#iw-panel{position:fixed;bottom:92px;right:24px;z-index:9999;width:340px;max-width:calc(100vw - 32px);height:480px;max-height:calc(100vh - 112px);border-radius:16px;overflow:hidden;display:flex;flex-direction:column;box-shadow:0 8px 32px rgba(0,0,0,.2);transform:scale(0);transform-origin:bottom right;transition:transform .22s cubic-bezier(.4,0,.2,1),opacity .22s;opacity:0;pointer-events:none;font-family:-apple-system,BlinkMacSystemFont,"Segoe UI",sans-serif;}#iw-panel.iw-open{transform:scale(1);opacity:1;pointer-events:all;}#iw-header{padding:14px 16px;display:flex;align-items:center;gap:10px;flex-shrink:0;}#iw-header .iw-avatar{width:32px;height:32px;border-radius:50%;background:rgba(255,255,255,.2);display:flex;align-items:center;justify-content:center;font-size:16px;}#iw-header .iw-title{color:#fff;font-weight:600;font-size:14px;flex:1;}#iw-header .iw-close{background:none;border:none;color:rgba(255,255,255,.8);cursor:pointer;font-size:20px;line-height:1;padding:0 4px;}#iw-header .iw-close:hover{color:#fff;}#iw-messages{flex:1;overflow-y:auto;padding:16px;display:flex;flex-direction:column;gap:10px;background:#f8f9fa;}.iw-msg{max-width:82%;padding:10px 14px;border-radius:16px;font-size:13.5px;line-height:1.5;word-break:break-word;}.iw-msg.iw-bot{background:#fff;color:#1a1a1a;border-bottom-left-radius:4px;align-self:flex-start;box-shadow:0 1px 4px rgba(0,0,0,.08);}.iw-msg.iw-user{color:#fff;border-bottom-right-radius:4px;align-self:flex-end;}.iw-typing{display:flex;gap:4px;padding:12px 14px;background:#fff;border-radius:16px;border-bottom-left-radius:4px;align-self:flex-start;box-shadow:0 1px 4px rgba(0,0,0,.08);}.iw-typing span{width:7px;height:7px;border-radius:50%;background:#aaa;animation:iw-bounce 1.2s infinite;}.iw-typing span:nth-child(2){animation-delay:.2s;}.iw-typing span:nth-child(3){animation-delay:.4s;}@keyframes iw-bounce{0%,60%,100%{transform:translateY(0);}30%{transform:translateY(-6px);}}#iw-footer{padding:10px 12px;background:#fff;border-top:1px solid #eee;display:flex;gap:8px;align-items:flex-end;flex-shrink:0;}#iw-input{flex:1;border:1px solid #ddd;border-radius:10px;padding:9px 12px;font-size:13.5px;resize:none;outline:none;max-height:100px;overflow-y:auto;font-family:inherit;line-height:1.4;}#iw-send{border:none;border-radius:10px;width:38px;height:38px;cursor:pointer;display:flex;align-items:center;justify-content:center;flex-shrink:0;transition:opacity .15s;}#iw-send:disabled{opacity:.45;cursor:default;}#iw-send svg{pointer-events:none;}';
  document.head.appendChild(style);

  var launcher = document.createElement('button');
  launcher.id = 'iw-launcher';
  launcher.setAttribute('aria-label', 'Open chat');
  launcher.style.background = ACCENT;
  launcher.innerHTML = '<svg width="26" height="26" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2" stroke-linecap="round" stroke-linejoin="round"><path d="M21 15a2 2 0 0 1-2 2H7l-4 4V5a2 2 0 0 1 2-2h14a2 2 0 0 1 2 2z"/></svg>';

  var panel = document.createElement('div');
  panel.id = 'iw-panel';
  panel.innerHTML = [
    '<div id="iw-header" style="background:' + ACCENT + '">',
    '<div class="iw-avatar">⬡</div>',
    '<div class="iw-title">' + BOT_NAME + '</div>',
    '<button class="iw-close" aria-label="Close">&times;</button>',
    '</div>',
    '<div id="iw-messages"></div>',
    '<div id="iw-footer">',
    '<textarea id="iw-input" rows="1" placeholder="Type a message…"></textarea>',
    '<button id="iw-send" style="background:' + ACCENT + '" aria-label="Send">',
    '<svg width="18" height="18" viewBox="0 0 24 24" fill="none" stroke="#fff" stroke-width="2.2" stroke-linecap="round" stroke-linejoin="round"><line x1="22" y1="2" x2="11" y2="13"/><polygon points="22 2 15 22 11 13 2 9 22 2"/></svg>',
    '</button></div>'
  ].join('');

  document.body.appendChild(launcher);
  document.body.appendChild(panel);

  var msgs  = panel.querySelector('#iw-messages');
  var input = panel.querySelector('#iw-input');
  var send  = panel.querySelector('#iw-send');
  var close = panel.querySelector('.iw-close');
  var open  = false;

  function toggle() {
    open = !open;
    panel.classList.toggle('iw-open', open);
    launcher.setAttribute('aria-expanded', open);
    if (open && msgs.children.length === 0) addMsg('bot', 'Hi! I\'m the InnovaWise Labs triage assistant. Tell me about your business challenge and I\'ll help figure out how AI automation can help.');
    if (open) setTimeout(function(){ input.focus(); }, 220);
  }

  function addMsg(role, text) {
    var d = document.createElement('div');
    d.className = 'iw-msg iw-' + role;
    if (role === 'user') d.style.background = ACCENT;
    d.textContent = text;
    msgs.appendChild(d);
    msgs.scrollTop = msgs.scrollHeight;
  }

  function showTyping() {
    var t = document.createElement('div');
    t.className = 'iw-typing';
    t.innerHTML = '<span></span><span></span><span></span>';
    msgs.appendChild(t);
    msgs.scrollTop = msgs.scrollHeight;
    return t;
  }

  function doSend() {
    var text = input.value.trim();
    if (!text || send.disabled) return;
    addMsg('user', text);
    input.value = '';
    input.style.height = 'auto';
    send.disabled = true; input.disabled = true;
    var t = showTyping();
    fetch(API_BASE + '/api/chat', {
      method: 'POST',
      headers: {'Content-Type': 'application/json'},
      body: JSON.stringify({message: text, session_id: getSession()})
    })
    .then(function(r){ if(!r.ok) throw new Error('HTTP '+r.status); return r.json(); })
    .then(function(d){ t.remove(); setSession(d.session_id); addMsg('bot', d.response); })
    .catch(function(e){ t.remove(); addMsg('bot', 'Sorry, something went wrong. Please try again.'); console.error('[IW]',e); })
    .finally(function(){ send.disabled=false; input.disabled=false; input.focus(); });
  }

  launcher.addEventListener('click', toggle);
  close.addEventListener('click', toggle);
  send.addEventListener('click', doSend);
  input.addEventListener('keydown', function(e){ if(e.key==='Enter'&&!e.shiftKey){e.preventDefault();doSend();} });
  input.addEventListener('input', function(){ this.style.height='auto'; this.style.height=Math.min(this.scrollHeight,100)+'px'; });
  document.addEventListener('click', function(e){ if(open&&!panel.contains(e.target)&&e.target!==launcher) toggle(); });
})();
